import React from "react";
import AddTodoModal from "./AddTodoModal";import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

const Todo = () => {
    return(
        <div>
           <div className="card text-white bg-secondary mb-3" style={{"maxWidth":"20rem"}}>

                <div className="card-body">
                    <h4 className="card-title">Secondary card title</h4>
                    <p className="card-text">Some quick example text to build on the card title and make up the bulk of the card's content.</p>
                </div>
            </div>
            <div className = "" style={{ position: "fixed", right: 50,  bottom: 50, zIndex: 1000}}>
                <button type="button" className="btn btn-secondary" data-bs-toggle="modal" data-bs-target="#exampleModal">Secondary</button>
            </div>
            <AddTodoModal />
            <ToastContainer
                position="top-right"
                autoClose={1500}
                hideProgressBar={false}
                newestOnTop={false}
                closeOnClick
                rtl={false}
                pauseOnFocusLoss
                draggable
                pauseOnHover
            />
        </div>    
    )
}

export default Todo;
